var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>도시관리국에서 범죄자들에게 통보한다. 이것은 마지막 경고다.</color>","JPN":"<color=#ffd34c>都市管理局より犯罪者たちに告ぐ。これは最後の警告だ。</color>","ENG":"<color=#ffd34c>City Management to all criminals. This is your last warning.</color>","TWN":"<color=#ffd34c>罪犯聽著，這是城市管理局最後一次警告。</color>"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>지금 무기를 버리고 투항하지 않으면, 전원 사살하겠다.</color>","JPN":"<color=#ffd34c>今すぐ武器を捨てて投降しなければ、全員射殺する。</color>","ENG":"<color=#ffd34c>Put down your weapons and surrender, or we will fire.</color>","TWN":"<color=#ffd34c>趕快棄械投降，否則將全面開火！</color>"},"stage":{"bg":"SKYLINE_NIGHT","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"……우릴 쫓는 추격대가 아직도 제법 많군.","JPN":"……我らを追う追撃隊がまだ結構いるな。","ENG":"...I see we still have company chasing after us.","TWN":"……沒想到有這麼多人在追趕我們。"},"stage":{"bg":"VEHICLE","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"결계를 제거해서 도시에 괴물을 풀고, 관리국의 본체가 이 사태에 신경 쓰지 못할 시기를 노렸는데도 말이야.","JPN":"結界を取り除いて都市に化け物を放ち、管理局の本体がこの事態に気づけない時期を狙ったというのに。","ENG":"Even with all the distractions of letting loose monsters after removing the city's barrier, thus keeping the Administration occupied.","TWN":"原本解除結界把怪物釋放到城市裡，就是要讓管理局沒餘力可以注意到我們。"},"stage":{"bg":"VEHICLE","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"걱정 마세요, 아버지. 제가 전부 죽이면 되니까요.","JPN":"心配いりません、お父様。私が全部殺せばいいだけのことです。","ENG":"Don't worry, father. I'll kill them all for you.","TWN":"父親別擔心，我把他們全都幹掉就好。"},"stage":{"bg":"VEHICLE","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"아직 서두르지 마라.","JPN":"早まるな。","ENG":"No need to hurry.","TWN":"先別急。"},"stage":{"bg":"VEHICLE","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"모처럼 이렇게 많은 피실험체가 모였는데, 그런 결과가 뻔한 실험은 아쉽지.","JPN":"せっかくここまでの数の被実験体が集まったのだ、結果が決まりきっている実験は物足りない。","ENG":"We are fortunate to have all these test subjects gathered today. A waste it would be to conduct experiments with obvious outcomes.","TWN":"難得有這麼多非實驗體聚在這裡，拿來做一翻兩瞪眼的實驗豈不是很可惜。"},"stage":{"bg":"VEHICLE","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>무기를 버리지 않고 침묵한 채 계속해서 이동 중입니다.</color>","JPN":"<color=#ffd34c>武器を捨てずに沈黙を守って移動を続けています。</color>","ENG":"<color=#ffd34c>They are ignoring our orders and marching forward.</color>","TWN":"<color=#ffd34c>罪犯沒有棄械，而是保持沉默繼續移動。</color>"},"stage":{"bg":"SKY_NIGHT","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L16_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>예상경로는 NAA-07…… 관리불가구역.</color>","JPN":"<color=#ffd34c>予想経路はNAA-07……管理不可エリア。</color>","ENG":"<color=#ffd34c>Estimated destination is NAA-07... The Unadministerable Zone.</color>","TWN":"<color=#ffd34c>預計路徑是NAA-07…… 拒絕管理區域。</color>"},"stage":{"bg":"NANAHARA_SEAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L19_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>타깃에겐 투항 의지가 없는 것으로 판단. 무력진압을 위해 대기 중인 병력을 투입합니다.</color>","JPN":"<color=#ffd34c>ターゲットには投降する意志がないものと判断。武力鎮圧のため、待機中の兵力を投入します。</color>","ENG":"<color=#ffd34c>Target shows no signs of forfeit. Deploying troops to arrest by force.</color>","TWN":"<color=#ffd34c>判斷目標沒有棄械投降的意願，投入全部兵力進行武力鎮壓。</color>"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SOLDIER_NPC_UNION_NULL","text":{"KOREA":"유다님, 이동 결계 시스템의 준비절차를 마쳤습니다.","JPN":"ユダ様、移動結界システムの用意が完了いたしました。","ENG":"Preparations for the mobile barrier system are complete, sir.","TWN":"報告，移動結界系統已經準備完畢。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_UNION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"다들 지금까지 잘해주었다. 이제 대업을 이룩하기까지 머지 않았다.","JPN":"皆の者、ここまでよくやってくれた。大業を成すまであとわずかだ。","ENG":"Well done, everyone. It is only a matter of time before we achieve greatness.","TWN":"大家這段時間都很努力，現在距離完成霸業只剩幾步之遙。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"그대들의 희생은 조국이 기억할 것이다.","JPN":"諸君の犠牲は祖国の歴史に残るだろう。","ENG":"The motherland will remember your sacrifice.","TWN":"國家會紀念你們的犧牲的。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":null,"text":{"KOREA":"북방합의체를 위해! 그 어떤 희생도 마다치 않으리!","JPN":"北方合意体のために！　どんな犠牲もいとわない！","ENG":"For the Northern Union! Life for the motherland!","TWN":"為了北方和議會！不惜任何犧牲！"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_UNION_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_CROWD_NOISE_04"},{"id":"L33_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>무슨 소리지? 벌써 교전이 일어났나?</color>","JPN":"<color=#ffd34c>何の音だ？　もう交戦が始まったのか？</color>","ENG":"<color=#ffd34c>Do you hear that? Is there a battle going on?</color>","TWN":"<color=#ffd34c>什麼聲音？開戰了嗎？</color>"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L34_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>범죄자들이 서로를 쏘고 있습니다!</color>","JPN":"<color=#ffd34c>犯罪者たちが仲間割れしています！</color>","ENG":"<color=#ffd34c>The criminals are shooting each other!</color>","TWN":"<color=#ffd34c>罪犯在對彼此開槍！</color>"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>이런, 저항을 포기하고 자결하는 건가?</color>","JPN":"<color=#ffd34c>なんだ、抵抗を諦め自殺しているのか？</color>","ENG":"<color=#ffd34c>Damn... Did they choose to perish rather than surrender?</color>","TWN":"<color=#ffd34c>可惡，他們情願自縊也不肯投降嗎？</color>"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L36_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>서둘러 움직여! 사로잡아야 한다!</color>","JPN":"<color=#ffd34c>急げ！　生け捕りにしなければ！</color>","ENG":"<color=#ffd34c>Quickly! Stop them!</color>","TWN":"<color=#ffd34c>動作快！把人抓起來！</color>"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L39_1","type":"dialog","speaker":"SOLDIER_NPC_UNION_NULL","text":{"KOREA":"결계옥이 피를 흡수하고 있습니다. 반응 에너지 점진적으로 상승 중.","JPN":"結界玉が血を取り込んでいます。反応エネルギー、徐々に上昇中。","ENG":"Akaitama is absorbing blood. Its energy readings are increasing.","TWN":"結界玉石正在吸收血液，反應能量逐漸上升中。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"SOLDIER_NPC_UNION_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"실패작들을 이용해 신을 깨울 수는 없지만, 결계의 에너지원으로는 활용할 수 있는 건가?","JPN":"失敗作どもを利用し神を目覚めさせることはできないが、結界のエネルギー源としては活用できるのか？","ENG":"I may not be able to awaken a god with the flawed, but will they be fit as an energy source for the barrier?","TWN":"意思是失敗品雖然無法喚醒神，但可以拿來當作結界的能量嗎？"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"훌륭하군. 관측 덕분에 불필요한 검증 절차가 줄었어.","JPN":"素晴らしい。観測のおかげで無駄な検証過程を省けた。","ENG":"Excellent. Observation has allowed me to skip the unnecessary verification process.","TWN":"非常好，觀測讓我們減少不必要的驗證程序。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"펠릭스 사령관. 우린 오늘 통제할 수 없는 그림자 따위보다 근본적인 힘을 활용할 법을 찾아냈소.","JPN":"フェリックス司令官。我らは今日、統制の効かないシャドウなどよりも根本的な力を活用する方法を見つけ出した。","ENG":"Commander Felix. We have found a method to utilize the essence of power, unlike those uncontrollable Shadows.","TWN":"菲利克斯司令官，我們今天找到的不是無法控制的暗影，而是可以運用那股力量的方法。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"그대가 이 광경을 보게 된다면 어떤 반응을 보일지 궁금하군.","JPN":"そなたがこの光景を見てどんな顔をするか楽しみだ。","ENG":"I wonder what your reaction would be to witness this magnificent event.","TWN":"我很好奇你看到這個景象會有什麼反應呢。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"SOLDIER_NPC_UNION_NULL","text":{"KOREA":"반응 에너지 최고조. 예측반경 2킬로미터까지 방출 가능합니다.","JPN":"反応エネルギー最高潮。予測半径2キロメートルまで放出できます。","ENG":"Reaction energy full. Able to affect a 2km radius.","TWN":"反應能量達到巔峰，預測可釋放至半徑2Km內的範圍。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"……가동한다.","JPN":"……稼働する。","ENG":"...Activate.","TWN":"……啟動。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"SOLDIER_NPC_UNION_NULL","text":{"KOREA":"이동 결계 시스템 가동.","JPN":"移動結界システム稼働。","ENG":"Activating mobile barrier system.","TWN":"啟動移動結界系統。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_UNION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>뭐야? 방금 무슨 일이 일어난 거지?</color>","JPN":"<color=#ffd34c>なんだ？　今何が起こった？</color>","ENG":"<color=#ffd34c>Huh? What's happening right now?</color>","TWN":"<color=#ffd34c>怎麼回事？發生什麼事？</color>"},"stage":{"bg":"SKY_NIGHT","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_UI_RECRUITMNET_HELICOPTER_START"},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>오퍼레이터! 진입하고 있던 병력들의 움직임이 잡히지 않는다. 어서 확인해봐!</color>","JPN":"<color=#ffd34c>オペレーター！　進入していた兵力の動きが捉えられない。早く確認しろ！</color>","ENG":"<color=#ffd34c>Operator! Unable to see movements of our troops. Please confirm!</color>","TWN":"<color=#ffd34c>領航員！沒辦法掌握到前進中的士兵動向，快進行確認！</color>"},"stage":{"bg":"SKY_NIGHT","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>사, 사라졌습니다. 식별태그는 남아있지만…… 대원들이 한 명도 보이지 않습니다.</color>","JPN":"<color=#ffd34c>き、消えました。識別タグは残っていますが……隊員が一人も見当たりません。</color>","ENG":"<color=#ffd34c>Th-they're gone. I can see their identification tags, but... they are nowhere to be seen!</color>","TWN":"<color=#ffd34c>消…消失了。識別標籤是還在……但隊員一個也沒看到。</color>"},"stage":{"bg":"SKY_NIGHT","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>뭐라고……?</color>","JPN":"<color=#ffd34c>何だと……？</color>","ENG":"<color=#ffd34c>What...?</color>","TWN":"<color=#ffd34c>你說什麼……？</color>"},"stage":{"bg":"SKY_NIGHT","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SOLDIER_NPC_UNION_NULL","text":{"KOREA":"관찰 결과. 반경내 적들의 완전소멸을 확인. 테스트는 성공적입니다.","JPN":"観察結果。半径内の敵の完全消滅を確認。テストは成功です。","ENG":"Observation results. All foes within range, annihilated. The test was a success.","TWN":"觀察結果，半徑內的敵人已全部殲滅，測試成功。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_UNION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"혈액을 식별해서 비인가 유기체를 분자 단위로 분해하는 천연의 무기라. 멋지군.","JPN":"血液を識別して非認可有機体を分子単位に分解する天然の武器か。素晴らしい。","ENG":"A natural weapon that can decompose unauthorized organisms to atoms with a blood identifier. Astounding.","TWN":"是可以分辨血液後將不認可的生物分解為分子的天然武器，厲害。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"……하지만 이건 시작일 뿐이죠.","JPN":"……でも、これは始まりに過ぎません。","ENG":"...However, this is just the beginning.","TWN":"……但這只是開始而已。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"그래, 신의 영혼에 실패작들의 피를 공급하는 것만으로 이 정도의 결과를 도출할 수 있다면……","JPN":"そう、神の魂に失敗作の血を取り入れるだけでこれほどの結果が出せたなら……","ENG":"Yes. Yet, getting this outcome with only the blood of the flawed...","TWN":"沒錯，光是以失敗品的血液供應神的靈魂，就可以導出這樣的結果……"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"그 다음 단계의 성과는 두 말할 필요 없겠지.","JPN":"その次の段階の成果は言うまでもないだろう。","ENG":"The next phase will surely be remarkable.","TWN":"那下一個階段的結果應該很明顯吧。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"결계를 유지하라. 이대로 나나하라 영지까지 진군한다.","JPN":"結界を維持しろ。このまま七原の領地まで進軍する。","ENG":"Maintain the barrier. We head towards Nanahara Territory.","TWN":"維持結界，繼續往七原領地前進。"},"stage":{"bg":"HIGHWAY_RAINY","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그 녀석들이 스스로 여기까지 찾아왔다고?","JPN":"あやつらが自らここまでやってきたと？","ENG":"They came all the way here?","TWN":"那些傢伙自己找到這裡來？"},"stage":{"bg":"GAUNTLET","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"흥, 차라리 잘됐군. 봉인역의 방어 시스템을 가동해라. 곤죽을 내버리자꾸나.","JPN":"ふん、むしろ好都合じゃ。封印域の防御システムを稼働せい。ぼこぼこにしてやるのじゃ。","ENG":"Hmph! Better for us. Activate the Seal Domain's defense system. We'll bash them to the ground.","TWN":"哼，來得正好！啟動封印域的防禦系統，來大掃除吧！"},"stage":{"bg":"GAUNTLET","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그들이 접근 중인 8봉인역은 오로치가 해방되었을 때 붕괴되었습니다.","JPN":"彼らが接近中である8封印域はオロチが解放されたとき崩壊しました。","ENG":"They are headed for the 8th Domain, which collapsed when Orochi was released.","TWN":"他們現在前往的8封印域，在釋放大蛇時便已瓦解，"},"stage":{"bg":"GAUNTLET","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"결계의 힘이 가장 약하게 작용하는 곳이기 때문에, 일부러 그곳을 노린 것 같군요.","JPN":"結界の力が一番弱く作用しているところなので､わざとそちらを狙ったようですね。","ENG":"They are trying to attack where the barrier is the weakest.","TWN":"那裡的結界力量是最弱，看來他們是故意挑那裡的。"},"stage":{"bg":"GAUNTLET","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"쳇…… 하바키, 그 애송이가 그런 정보까지 팔아넘긴 건가?","JPN":"ちっ……覇吐、あの若造がそんな情報まで売り渡していたのか？","ENG":"Tch, Habaki... Did he tell them about that too?","TWN":"嘖……幅木那小子連這種事也告訴他們嗎？"},"stage":{"bg":"GAUNTLET","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"어쩌면 그 가짜 무녀를 이용해 알아냈을 지도 모르죠.","JPN":"もしかしたらあの偽の巫女を利用して知ったのかもしれません。","ENG":"Or maybe, their fake priestess somehow found out about it.","TWN":"也可能是利用那個冒牌巫女得知的。"},"stage":{"bg":"GAUNTLET","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"그리고 정찰을 통해 그들이 결계옥을 소지하고 있는 것을 확인했습니다.","JPN":"それから、偵察で彼らが結界玉を持っているのを確認いたしました。","ENG":"Furthermore, our scouting has confirmed they are in possession of Akaitama.","TWN":"另外打探時發現結界玉石確實在他們手上。"},"stage":{"bg":"GAUNTLET","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"그렇다면 망설일 필요도 없겠군요. 지금 당장 놈들을 치시죠.","JPN":"それなら悩む必要はありませんね。今すぐ奴らを打ちましょう。","ENG":"Then we waste no more time. We must strike now.","TWN":"那還猶豫什麼？立刻發動攻擊吧！"},"stage":{"bg":"GAUNTLET","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"그렇게 쉽게 말할 문제가 아니다.","JPN":"そう簡単な問題ではない。","ENG":"It's easier said than done.","TWN":"事情沒這麼簡單。"},"stage":{"bg":"GAUNTLET","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"예……?","JPN":"はい……？","ENG":"What...?","TWN":"什麼……？"},"stage":{"bg":"GAUNTLET","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"녀석들이 결계 안으로 들어왔다는 건, 애초에 놈의 병사들이 처음부터 우리와 같은 피를 몸에 지니고 있었다는 거다.","JPN":"奴らが結界の中に入ってきたということは、そもそも奴の兵士たちに私たちと同じ血が流れていたということじゃ。","ENG":"They were able to pass through the barrier because their soldiers carried the same blood as us from the start.","TWN":"他們可以進到結界裡，就表示他們士兵體內的血和我們是一樣的。"},"stage":{"bg":"GAUNTLET","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"이곳에서 하바키를 돕기 전부터 모든 걸 계획하고 있었다는 뜻이지.","JPN":"この地で覇吐に協力する以前からすべてを計画していたのじゃな。","ENG":"Which means that they planned all this out even before Habaki joined them.","TWN":"早在協助幅木之前，這一切都是他們已經計畫好的。"},"stage":{"bg":"GAUNTLET","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"지금까지의 정황대로라면, 저들의 다음 목적은 결계옥을 이용해 신을 깨우는 것이겠군요.","JPN":"今までの状況から見ると、彼らの次の目的は結界玉を利用し神を目覚めさせることでしょうね。","ENG":"From the looks of it, their next objective is to use Akaitama to awaken the god.","TWN":"照目前的走向，他們下一個目標應該是利用結界玉石喚醒神。"},"stage":{"bg":"GAUNTLET","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L32_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"아무리 결계옥이 신의 영혼으로 만들어졌다고 해도……. 그걸 이용해 신을 되살릴 방법이 있는 겁니까?","JPN":"いくら結界玉が神の魂でできていると言っても……それを利用して神を蘇らせることなどできるのですか？","ENG":"Even knowing that Akaitama is made of the god's soul... could it be used to resurrect one?","TWN":"雖然結界玉石是利用神的靈魂做成的……但有辦法利用它喚醒神嗎？"},"stage":{"bg":"GAUNTLET","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L34_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"불가능한 얘기는 아니지.","JPN":"不可能ではない。","ENG":"It's not impossible.","TWN":"並非不可能。"},"stage":{"bg":"GAUNTLET","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"신을 잠재우기 위해 무녀가 피를 흘리듯이, 저승에 뿌리를 둔 신을 깨우고자 한다면 한때 저승에 속했던 인간들의 피가 있으면 돼.","JPN":"神を鎮めるために巫女が血を流すように、冥府の神を目覚めさせるにはかつて冥府にいた人間の血があればよい。","ENG":"Just as a priestess sheds blood to put the god into slumber, all they need to awaken the Nether God is the blood of humans who were once a part of the Afterlife.","TWN":"就像要有巫女的血才能讓神沉睡，要想喚醒地獄裡的神，只要有曾經屬於地獄的人類之血就好。"},"stage":{"bg":"GAUNTLET","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"문제는 그렇게 해서 깨어나는 것이 평범한 신이 아니라, 이성 없는 흉신이라는 것이겠지만.","JPN":"問題はそうやって目覚めるのが普通の神ではなく、理性のない凶神であることじゃ。","ENG":"The problem is, however, that the god they are resurrecting is not a god, but a Fiend.","TWN":"只是問題是這樣喚醒的不是一般的神，而是沒有理性的凶神。"},"stage":{"bg":"GAUNTLET","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"저들의 계획에 우리의 피가 필요하다면, 굳이 저들을 상대해줄 이유도 없지 않습니까?","JPN":"彼らの計画に私たちの血が必要だというなら、あえて彼らの相手をする理由もないのでは？","ENG":"If their plan requires our blood, then there is no reason for us to fight them, no?","TWN":"如果他們的計畫需要我們的血，那我們沒理由硬要和他們正面衝突吧？"},"stage":{"bg":"GAUNTLET","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"이유는 충분합니다. 결계옥이 저들의 손에 있으니까요.","JPN":"理由は十分です。結界玉が彼らの手にありますから。","ENG":"There is more than enough reason. They have Akaitama in hand.","TWN":"理由很明確，因為結界玉石在他們手裡。"},"stage":{"bg":"GAUNTLET","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"놈들은 승부수를 던졌어. 저걸 되찾지 못하면 나나하라 당주는 결계를 유지하다가 영혼을 잃을 테고, 결계 또한 사라지고 만다.","JPN":"奴らは勝負に出た。あれを取り返さなければ七原当主は結界の維持を続けていずれは魂を失うであろうし、結界もまた消えてしまう。","ENG":"They've thrown down the gauntlet. If we don't get Akaitama back, Lady Nanahara will lose her soul trying to keep the barrier up, and the barrier will eventually vanish along with her soul.","TWN":"他們打算在這裡一決勝負。如果不能找回結界玉石，七原堂主就會因為維持結界而失去靈魂，而結界最後也會消失。"},"stage":{"bg":"GAUNTLET","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"GAUNTLET","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"내버려두건, 놈들의 계획에 어울리건 최악의 상황은 피하기 힘들어.","JPN":"放っておこうが、奴らの手に乗ろうが、最悪の状況は避けられん。","ENG":"Fighting them or not, it will be difficult to avoid the worst possible outcome.","TWN":"無論是放任他們，或是配合他們的計畫，都無法避免最壞的情況發生。"},"stage":{"bg":"GAUNTLET","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"녀석들이 무슨 수로 신의 영혼을 통제할 작정인지는 모르겠다만…… ","JPN":"奴らがどんな手で神の魂を操るつもりなのかはわからぬが…… ","ENG":"I don't know how they are going to control the god's soul, but...","TWN":"雖然不知道他們打算用什麼辦法控制神的靈魂……"},"stage":{"bg":"GAUNTLET","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"최종 판단은 나나하라 당주에게 맡기는 수밖에.","JPN":"最後の判断は七原当主に任せるしかあるまい。","ENG":"We have to leave it for Lady Nanahara to decide.","TWN":"但最後的決定權在七原堂主手裡。"},"stage":{"bg":"GAUNTLET","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"상황은 이해했습니다.","JPN":"状況は理解しました。","ENG":"I understand the situation.","TWN":"情況我了解了。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"나나하라 가문연합은 저들과 맞서 싸워 결계옥을 회수할 것입니다.","JPN":"七原家連合は彼らに立ち向かい、結界玉を回収いたします。","ENG":"The Nanahara Family Alliance will fight them and retrieve Akaitama.","TWN":"七原家族聯盟將正面迎戰，要奪回結界玉石。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"결정은 났군. 그럼 얼른 병사들을 움직여서……","JPN":"決まったのう。それではさっそく兵士を動かし……","ENG":"It's decided. Then I'll order the soldiers and–","TWN":"既然已經做出決定，那就趕快調動士兵……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"다만, 저도 함께 동행하겠습니다.","JPN":"しかし、私も共に行動いたします。","ENG":"However, I will also accompany the troops.","TWN":"前提是我也要一起行動。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"당주님께서 직접 움직이시는 건 너무 위험합니다!","JPN":"当主自ら行動するのはあまりにも危険です！","ENG":"My lady! It is too dangerous for you to head into battle!","TWN":"堂主親自行動太危險了！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"저도 같은 의견입니다. 적의 함정에 당주님까지 나서실 필요는 없습니다.","JPN":"私も同意見です。敵の罠にご当主様までかかる必要はございません。","ENG":"I have to agree. There is no need for you to head straight into their trap.","TWN":"我也這麼認為，明擺著是敵人的陷阱，堂主沒必要自投羅網。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저들은 만반의 준비를 갖추었고, 쉽게 돌아갈 생각 또한 없을 것입니다.","JPN":"彼らは万全の準備を整えているでしょうし、簡単には退かないでしょう。","ENG":"They come well prepared and will not back down, I believe.","TWN":"他們既然已經做好萬全的準備，想必是不會罷休的。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그렇다면 저희도 최선을 다해 응수해야만 해요.","JPN":"であれば、私たちも最善を尽くして立ち向かわなければなりません。","ENG":"Then, we must do our best to respond.","TWN":"那我們也必須全力應戰。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"이번엔 도시의 주민들을 지키는 그런 작전이 아니다.","JPN":"今回は都市の住民を守るような作戦ではない。","ENG":"This time, it's not just about protecting the residents.","TWN":"這次的作戰目標不是保護市民，"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"자칫 전멸할 수도 있는 싸움에 나나하라의 직계를 둘 다 내보낼 수는 없어.","JPN":"一歩間違えれば全滅するかもしれない戦いに七原の直系を二人とも行かせるわけにはいかぬ。","ENG":"I am against the idea of sending both Nanahara descendants into battle when there is a chance we might lose the both of you.","TWN":"而且稍有不慎就會全軍覆沒，我不能讓七原的二個直系後裔都同行。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그건 걱정 마십시오. 나나하라 치후유는 이번 작전에 출전하지 않습니다.","JPN":"それはご心配なく。七原千冬は今回の作戦に参加しません。","ENG":"No need to worry about that. Nanahara Chifuyu will not be partaking.","TWN":"這一點您不用擔心，七原千冬不會參與這次作戰。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"……당주님?!","JPN":"……当主！？","ENG":"...Lady Nanahara?!","TWN":"……堂主？！"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"이건 당주로서의 명령입니다, 치후유.","JPN":"これは当主としての命令です、千冬。","ENG":"This is a direct order as head of the Nanahara family, Chifuyu.","TWN":"這是堂主的命令，千冬。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저는 더 이상 바람의 목소리를 듣지 못하지만, 일찌감치 알고 있는 미래가 한 가지 있어요.","JPN":"私はもう風の声を聞くことはできませんが、その前から知っている未来がもう一つあるのです。","ENG":"I am not able to hear the voice of wind any more, but there is a future that I have known from early on.","TWN":"雖然我再也聽不見風聲，我很久以前就知道一個未來。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L15_1","type":"dialog","speaker":"CHIFUYU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그러니 나나하라의 직계는 저 혼자만 움직일 것입니다.","JPN":"ですから、七原の直系は私一人だけ動きます。","ENG":"So, it is only I who will be entering the battle.","TWN":"所以，七原的直系後裔中只會有我一個人同行。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CHIFUYU_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"DRAGON_NANAHARA_NULL_NULL","text":{"KOREA":"……알겠다. 정 그것이 나나하라 당주의 뜻이라면.","JPN":"……わかった。それが七原当主の考えであるなら。","ENG":"...Very well. If that is was you wish.","TWN":"……好，若七原堂主執意如此。"},"stage":{"bg":"NANAHARA_NORMAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DRAGON_NANAHARA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>저희는 현재 범죄자들의 행적을 추적하기 위해 중부도시에 위치한 NAA-07…… 통칭 관리불가구역 주변 상공에 도착해있습니다.</color>","JPN":"<color=#ffd34c>私たちは現在、犯罪者たちの動きを追跡するため中部都市に位置しているNAA-07……通称管理不可エリア周辺の上空に到着しました。</color>","ENG":"<color=#ffd34c>We're currently hovering near NAA-07 airspace, a.k.a the Unadministerable Zone... to track the criminal's whereabouts.</color>","TWN":"<color=#ffd34c>我們為追蹤罪犯的動向而來到位於中部城市的NAA-07……統稱為拒絕管理區域的周圍上空。</color>"},"stage":{"bg":"SKY_NIGHT","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L22_1","type":"dialog","speaker":null,"text":{"KOREA":"<color=#ffd34c>도시관리국의 정보에 따르면, 범죄자들은 태스크포스라는 법적 규제의 맹점을 이용해 오랜 기간 위조된 신분으로 활동하며……</color>","JPN":"<color=#ffd34c>都市管理局の情報によると、犯罪者たちはタスクフォースという法律の盲点を利用し、長期間身分を偽って活動し……</color>","ENG":"<color=#ffd34c>According to intel from City Management, these criminals have long used a loophole in the TASKFORCE legal regulations to work under false identification...</color>","TWN":"<color=#ffd34c>根據城市管理局提供的資訊，罪犯利用特遣勢力法規的漏洞，長期以來一直以偽造的身份行動……</color>"},"stage":{"bg":"SKY_NIGHT","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"여전히 구경꾼들이 많군.","JPN":"相変わらず野次馬が多いな。","ENG":"Still, a lot of spectators, I see.","TWN":"還是有很多看熱鬧的人呢。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"이걸로 아버지의 위업을 더 많은 사람들이 목격하고, 또 우러르게 될 거예요.","JPN":"今回を機にお父様の偉業をもっとたくさんの人が目撃し、崇めることになるでしょう。","ENG":"With this, many will witness and be overwhelmed by father's feat.","TWN":"這樣就會有更多的人見證父親的霸業，並且崇拜父親。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"그래, 그렇게 되겠지.","JPN":"ああ、そうなるだろう。","ENG":"Yes, I believe so.","TWN":"是吧，我想是的。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"레노어. 너는 내가 만든 산물로서 할 일을 충실히 해주었다.","JPN":"レノア。お前は私が作った道具としての役目をきっちり果たしてくれた。","ENG":"Lenore. You have faithfully fulfilled your duty as my creation.","TWN":"蕾諾雅，身為我的創造物，你一直都非常盡忠職守。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"넌 나의 자랑스러운 검이다.","JPN":"お前は私の自慢すべき剣だ。","ENG":"You are my noble blade.","TWN":"你是我引以為傲的劍。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"아아…… 천만에요, 아버지.","JPN":"ああ……とんでもありません、お父様。","ENG":"Ah... I am truly honored, father.","TWN":"唔嗯……父親過獎了。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"태어나서 햇볕도 제대로 못보던 절 이렇게나 강하게 만들어주신 건 아버지인 걸요.","JPN":"生まれて日を見ることすらままならなかった私をこのように強くしてくださったのはお父様ですもの。","ENG":"You are the one who brought me into the light and made me strong, father.","TWN":"是父親讓一出生就見不得光的我，變得如此強大。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SOLDIER_NPC_UNION_NULL","text":{"KOREA":"봉인역으로 진입 중입니다. 이동 결계와의 싱크로율은 59%로 다소 불안정. 충돌 시 파괴될 위험이 있습니다.","JPN":"封印域に進入しています。移動結界とのシンクロ率は59%で多少不安定。衝突時破壊される恐れがあります。","ENG":"Entering Seal Domain. Synchronization with the mobile barrier is rather unstable at 59%. Collision might destroy ours, sir.","TWN":"正進入封印域，與移動結界的相似率為59%，難免會有些不穩定，碰撞時恐怕會有瓦解的風險。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_UNION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"실패하지 않을 테니 멈추지 마라. 그대로 진입한다.","JPN":"失敗することはない、止まるな。そのまま進入する。","ENG":"We will not fail. We proceed onward.","TWN":"不會失敗的，不要停，繼續前進。"},"stage":{"bg":"FOREST_NORMAL_02","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SOLDIER_NPC_UNION_NULL","text":{"KOREA":"……진입 성공.","JPN":"……進入に成功。","ENG":"...Entry successful.","TWN":"……成功進入。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SOLDIER_NPC_UNION_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"이걸로 외부의 방해를 받을 일은 없다.","JPN":"これで外部から邪魔されることはない。","ENG":"External hindrances are now nonexistent.","TWN":"這樣就不會受到外界的干擾了。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"드디어, 최종실험을 위한 최적의 무대가 완성되었군.","JPN":"やっと、最終実験を行うための最適の舞台が整った。","ENG":"Finally, everything is coming together for the final test.","TWN":"專屬於最終實驗的最佳舞台終於大功告成。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L42_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"다시 만났네, 원본.","JPN":"また会えたわね、オリジナル。","ENG":"We meet again, Original.","TWN":"又見面囉，正本。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"당신들은 이곳에 발을 들여선 안 됩니다.","JPN":"あなたたちはここに足を踏み入れてはいけません。","ENG":"You have no right to step foot here.","TWN":"這裡不是你們可以進來的地方。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"하지만 이렇게 들어와버린 걸?","JPN":"もう入ってきちゃったけど？","ENG":"But we already have.","TWN":"但我們已經進來咧？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"이 정도면 우리에게도 너희 신을 부릴 자격이 있다는 뜻 아니겠니?","JPN":"この程度なら私たちにもお前たちの神を操る資格があるということじゃないかしら？","ENG":"So don't you think we also have the right to handle your god as well?","TWN":"這樣的話，是不是表示我們也有資格使喚你們的神呢？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"이승에 존재해서는 안 될 신을 불러들이면, 현실에 돌이킬 수 없는 큰 구멍이 생기고 만다.","JPN":"この世に存在してはならない神を呼び入れれば､現実に取り返しのつかない大きな穴ができてしまう。","ENG":"By summoning a god that has no purpose, you are causing irreversible damage to this world.","TWN":"要是把不能存在於現世的神召喚出來，現世就會產生無法彌補的黑洞。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"네놈이 정말로 미래를 볼 수 있다면 그 정도는 이미 알고 있겠지.","JPN":"お前が本当に未来を見ることができるなら､それくらいはすでに知っているだろう。","ENG":"If you really can foresee the future, then I am sure you already know that much.","TWN":"若你真能看到未來，應該很清楚吧？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L49_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"아핫, 호들갑은~","JPN":"あはっ、おおげさね～","ENG":"Hah, you and your worries!","TWN":"哈哈，真囉嗦～"},"stage":{"bg":"NANAHARA_SEAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"어차피 이면세계라면 이미 잔뜩 있는 구멍투성이 세상이잖아?","JPN":"どうせ裏世界はすでに穴だらけじゃない？","ENG":"Isn't Counterside already damaged beyond repair?","TWN":"反正異界早就已經是個千瘡百孔的世界啦？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LENORE_UNION_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":"LENORE_UNION_NULL_NULL","text":{"KOREA":"안 그래? 무능한 무녀 아가씨?","JPN":"違う？　無能な巫女さん？","ENG":"Isn't that right? Miss Incompetent Priestess?","TWN":"不是嗎？無能的巫女？"},"stage":{"bg":"NANAHARA_SEAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"NANAHARA_SEAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"저는 더이상 미래를 들을 수 없습니다.","JPN":"私はもう未来を聞くことができません。","ENG":"I cannot hear the future anymore.","TWN":"雖然我已經聽不見未來，"},"stage":{"bg":"NANAHARA_SEAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"하지만 당신들이 목적을 위해 버려선 안 될 것들을 포기했다는 건 분명히 알고 있어요.","JPN":"ですが、あなたたちが目的のために捨ててはならないものを捨てたことははっきりとわかります。","ENG":"Nevertheless, I do know for certain that you abandoned many things you should not throw away for the sake of your purpose.","TWN":"但是我清楚地知道，你們為達到目的而拋棄不該丟棄的東西。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"대화는 이쯤하지.","JPN":"話はこれくらいにしよう。","ENG":"Enough talking.","TWN":"話就說到這裡。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GENERAL_NPC_NOA_NULL","text":{"KOREA":"이 신기를 되찾고 싶다면, 죽을 각오로 덤벼야 할 것이오.","JPN":"この神器を取り戻したければ、死ぬ覚悟で来い。","ENG":"If you want this Sacred Treasure, I suggest you come ready to lose your life.","TWN":"若想拿回這個神器，那就做好必死的準備，放馬過來吧。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GENERAL_NPC_NOA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"……사나에, 제가 8봉인역을 정화하여 저들의 결계를 무력화하겠습니다.","JPN":"……早苗、私が8封印域を浄化し彼らの結界を無力化します。","ENG":"...Sanae, I will purify the 8th Seal Domain and nullify their barrier.","TWN":"……早苗，我來淨化8封印域讓他們的結界失效。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"CHINATSU_NANA_NULL_NULL","text":{"KOREA":"그러니 그동안 시간을 벌어주세요.","JPN":"ですから、その間時間を稼いでください。","ENG":"In the meanwhile, please buy me some time.","TWN":"請你幫我爭取時間。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"SANAE_NANA_NULL_NULL","text":{"KOREA":"알겠습니다. 저희에게 맡겨주시지요.","JPN":"かしこまりました。お任せください。","ENG":"Understood. Leave it to me.","TWN":"好的，請交給我們。"},"stage":{"bg":"NANAHARA_SEAL","bgm":"UI_LOGIN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"CHINATSU_NANA_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SANAE_NANA_NULL_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};